const j = $input.first().json;

// ============================================
// SUBJECT DINÂMICO
// ============================================
let subject = '';

// Função auxiliar para montar o identificador da unidade
function getIdentificador() {
  let id = '';
  if (j.numero_bloco) {
    id += ` - Bloco ${j.numero_bloco}`;
  }
  if (j.numero_unidade) {
    id += ` - Unidade ${j.numero_unidade}`;
  }
  return id;
}

if (j.tipo_documento) {
  const tipo = j.tipo_documento.toLowerCase();
  const identificador = getIdentificador();

  if (tipo.includes('multa')) {
    subject = `MULTA - ${j.nome_condominio || 'Condomínio'}${identificador}`;
  } else if (tipo.includes('notificação') || tipo.includes('notificacao')) {
    subject = `NOTIFICAÇÃO DE INFRAÇÃO - ${j.nome_condominio || 'Condomínio'}${identificador}`;
  } else if (tipo.includes('advertência') || tipo.includes('advertencia')) {
    subject = `ADVERTÊNCIA - ${j.nome_condominio || 'Condomínio'}${identificador}`;
  } else if (tipo.includes('cobrança') || tipo.includes('cobranca')) {
    subject = `COBRANÇA - ${j.nome_condominio || 'Condomínio'}${identificador}`;
  } else {
    subject = `${j.tipo_documento} - ${j.nome_condominio || 'Condomínio'}${identificador}`;
  }
} else {
  const identificador = getIdentificador();
  subject = `Comunicado - ${j.nome_condominio || 'Condomínio'}${identificador}`;
}

// ============================================
// HTML
// ============================================
const html = `
<!doctype html>
<html lang="pt-BR">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>${j.tipo_documento || ''} — ${j.nome_condominio || ''}</title>
  </head>
  <body style="margin:0;padding:0;background:#f5f3ee;font-family:Georgia,'Times New Roman',serif;color:#1a2030;">
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#f5f3ee;padding:32px 12px;">
      <tr>
        <td align="center">
          <table role="presentation" width="600" cellpadding="0" cellspacing="0" border="0" style="max-width:600px;width:100%;background:#ffffff;border:1px solid #e5e0d6;border-radius:6px;overflow:hidden;">

            <!-- Header -->
            <tr>
              <td style="background:#0d2a4a;padding:28px 32px;text-align:center;">
                ${j.logo_condominio ? `
                <div style="margin-bottom:12px;">
                  <img src="${j.logo_condominio}" alt="${j.nome_condominio || ''}" style="max-height:56px;max-width:180px;display:inline-block;" />
                </div>
                ` : ''}
                <div style="font-family:Georgia,'Times New Roman',serif;color:#ffffff;font-size:20px;letter-spacing:0.08em;font-weight:600;">
                  MONTEIRO RAMALHO
                </div>
                <div style="margin-top:4px;font-family:Arial,Helvetica,sans-serif;color:#c9a84c;font-size:10px;letter-spacing:0.3em;text-transform:uppercase;">
                  Advogados Associados
                </div>
              </td>
            </tr>
            <tr><td style="height:3px;background:#c9a84c;"></td></tr>

            <!-- Intro -->
            <tr>
              <td style="padding:36px 32px 8px 32px;">
                <p style="margin:0 0 8px 0;font-family:Arial,Helvetica,sans-serif;font-size:12px;letter-spacing:0.14em;text-transform:uppercase;color:#6b7280;">
                  ${j.tipo_documento || ''}
                </p>
                <h1 style="margin:0 0 12px 0;font-family:Georgia,'Times New Roman',serif;font-size:24px;line-height:1.3;color:#0d2a4a;font-weight:600;">
                  ${j.nome_condominio || ''}
                </h1>
                <p style="margin:0 0 20px 0;font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.6;color:#1a2030;">
                  Prezado(a) condômino(a)${j.numero_bloco ? ` do <strong>Bloco ${j.numero_bloco}${j.numero_unidade ? ` — Unidade ${j.numero_unidade}` : ''}</strong>` : (j.numero_unidade ? ` da <strong>Unidade ${j.numero_unidade}</strong>` : '')},<br/>
                  ${j.data_infracao ? `segue abaixo o resumo da ocorrência registrada em <strong>${j.data_infracao}</strong>.` : 'segue abaixo o resumo da ocorrência registrada.'} O documento completo está disponível no link ao final.
                </p>
              </td>
            </tr>

            <!-- Card infração -->
            <tr>
              <td style="padding:0 32px 8px 32px;">
                <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#f5f3ee;border:1px solid #e5e0d6;border-radius:4px;">
                  ${j.infracao ? `
                  <tr>
                    <td style="padding:18px 20px;">
                      <div style="font-family:Arial,Helvetica,sans-serif;font-size:11px;letter-spacing:0.14em;text-transform:uppercase;color:#6b7280;margin-bottom:6px;">
                        Infração cometida
                      </div>
                      <div style="font-family:Georgia,'Times New Roman',serif;font-size:15px;line-height:1.6;color:#1a2030;">
                        ${j.infracao}
                      </div>
                    </td>
                  </tr>
                  ` : ''}
                  ${j.regimento_clausula ? `
                  <tr><td style="border-top:1px solid #e5e0d6;"></td></tr>
                  <tr>
                    <td style="padding:18px 20px;">
                      <div style="font-family:Arial,Helvetica,sans-serif;font-size:11px;letter-spacing:0.14em;text-transform:uppercase;color:#6b7280;margin-bottom:6px;">
                        Disposição regimental violada
                      </div>
                      <div style="font-family:Georgia,'Times New Roman',serif;font-size:14px;line-height:1.6;color:#1a2030;">
                        ${j.regimento_artigo ? `<strong>Art. ${j.regimento_artigo}</strong> — ` : ''}${j.regimento_clausula}
                      </div>
                    </td>
                  </tr>
                  ` : ''}
                </table>
              </td>
            </tr>

            ${j.prazo_regularizacao ? `
            <!-- Prazo -->
            <tr>
              <td style="padding:16px 32px 0 32px;">
                <p style="margin:0;font-family:Arial,Helvetica,sans-serif;font-size:13px;line-height:1.6;color:#1a2030;">
                  <strong style="color:#0d2a4a;">Prazo para regularização:</strong> ${j.prazo_regularizacao}
                </p>
              </td>
            </tr>
            ` : ''}

            ${j.documento_url ? `
            <!-- Botão -->
            <tr>
              <td style="padding:28px 32px 8px 32px;text-align:center;">
                <a href="${j.documento_url}"
                   style="display:inline-block;background:#0d2a4a;color:#ffffff;text-decoration:none;padding:14px 28px;border-radius:4px;font-family:Arial,Helvetica,sans-serif;font-size:14px;font-weight:600;letter-spacing:0.04em;">
                  Abrir documento completo
                </a>
              </td>
            </tr>
            ` : ''}

            <!-- Footer -->
            <tr><td style="border-top:1px solid #e5e0d6;"></td></tr>
            <tr>
              <td style="padding:20px 32px;background:#fafaf7;text-align:center;">
                <p style="margin:0 0 4px 0;font-family:Georgia,'Times New Roman',serif;font-size:13px;color:#0d2a4a;font-weight:600;">
                  ${j.nome_condominio || ''}
                </p>
                ${j.endereco_condominio ? `
                <p style="margin:0 0 2px 0;font-family:Arial,Helvetica,sans-serif;font-size:11px;color:#6b7280;">
                  ${j.endereco_condominio}${j.cidade ? ` · ${j.cidade}` : ''}
                </p>
                ` : (j.cidade ? `
                <p style="margin:0 0 2px 0;font-family:Arial,Helvetica,sans-serif;font-size:11px;color:#6b7280;">
                  ${j.cidade}
                </p>
                ` : '')}
                ${j.numero_cnpj ? `
                <p style="margin:0 0 8px 0;font-family:Arial,Helvetica,sans-serif;font-size:11px;color:#6b7280;">
                  CNPJ ${j.numero_cnpj}
                </p>
                ` : ''}
                ${j.nome_sindico ? `
                <p style="margin:0;font-family:Arial,Helvetica,sans-serif;font-size:11px;color:#6b7280;">
                  ${j.nome_sindico} — síndico${j.data_submissao ? ` · ${j.data_submissao}` : ''}
                </p>
                ` : (j.data_submissao ? `
                <p style="margin:0;font-family:Arial,Helvetica,sans-serif;font-size:11px;color:#6b7280;">
                  ${j.data_submissao}
                </p>
                ` : '')}
              </td>
            </tr>

          </table>
        </td>
      </tr>
    </table>
  </body>
</html>
`;

// ============================================
// RETORNO COM SUBJECT + HTML
// ============================================
return [{ 
  json: { 
    subject: subject,
    html: html
  } 
}];

